1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Branch target: -1=no branch, 0=exit, >0=line number (1-based)
12	int branch_target;
13	
14	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
15	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
16	int qled_shadow;
17	
18	// ---- Call stack for user function recursion ----
19	
20	// Save AST state per call frame (CALL_MAX * AST_MAX = 8 * 64 = 512)
21	int save_ntype[512];
22	int save_nval[512];
23	int save_nleft[512];
24	int save_nright[512];
